+    #[test]
+    fn selection_moved_syncs_virtualized_state() {
+        let mut app = CassApp::default();
+        app.panes.push(AgentPane {
+            agent: "claude_code".into(),
+            hits: vec![
+                SearchHit {
+                    title: "A".into(),
+                    snippet: "".into(),
+                    content: "".into(),
+                    content_hash: 0,
+                    score: 1.0,
+                    agent: "claude_code".into(),
+                    source_path: "/a".into(),
+                    workspace: "/w".into(),
+                    workspace_original: None,
+                    created_at: None,
+                    line_number: None,
+                    match_type: Default::default(),
+                    source_id: "local".into(),
+                    origin_kind: "local".into(),
+                    origin_host: None,
+                },
+                SearchHit {
+                    title: "B".into(),
+                    snippet: "".into(),
+                    content: "".into(),
+                    content_hash: 1,
+                    score: 0.9,
+                    agent: "claude_code".into(),
+                    source_path: "/b".into(),
+                    workspace: "/w".into(),
+                    workspace_original: None,
+                    created_at: None,
+                    line_number: None,
+                    match_type: Default::default(),
+                    source_id: "local".into(),
+                    origin_kind: "local".into(),
+                    origin_host: None,
+                },
+                SearchHit {
+                    title: "C".into(),
+                    snippet: "".into(),
+                    content: "".into(),
+                    content_hash: 2,
+                    score: 0.8,
+                    agent: "claude_code".into(),
+                    source_path: "/c".into(),
+                    workspace: "/w".into(),
+                    workspace_original: None,
+                    created_at: None,
+                    line_number: None,
+                    match_type: Default::default(),
+                    source_id: "local".into(),
+                    origin_kind: "local".into(),
+                    origin_host: None,
+                },
+            ],
+            selected: 0,
+            total_count: 3,
+        });
+        app.active_pane = 0;
+
+        // Move down twice
+        let _ = app.update(CassMsg::SelectionMoved { delta: 1 });
+        assert_eq!(app.panes[0].selected, 1);
+        let _ = app.update(CassMsg::SelectionMoved { delta: 1 });
+        assert_eq!(app.panes[0].selected, 2);
+
+        // Move up once
+        let _ = app.update(CassMsg::SelectionMoved { delta: -1 });
+        assert_eq!(app.panes[0].selected, 1);
+
+        // Jump to end
+        let _ = app.update(CassMsg::SelectionJumped { to_end: true });
+        assert_eq!(app.panes[0].selected, 2);
+
+        // Jump to start
+        let _ = app.update(CassMsg::SelectionJumped { to_end: false });
+        assert_eq!(app.panes[0].selected, 0);
+
+        // VirtualizedListState should be in sync
+        let state = app.results_list_state.borrow();
+        assert_eq!(state.selected, Some(0));
+    }
